let lines = global.get('linesState');
let globalState = global.get('globalState') || { isShiftBreak: false, shiftDuration: 3600 };

if (!lines) {
  lines = {};
  for(let i=1; i<=37; i++) {
     let id = i < 10 ? 'L0'+i : 'L'+i;
     lines[id] = { 
        partsCount: 0, scrapCount: 0, 
        taktTime: 1, autoTakt: true, 
        isRunning: true, activeFault: null,
        targetQuantity: 1200,
        shiftDuration: 3600,
        operatingTime: 0, downtime: 0
     };
  }
}

let lastTick = global.get('lastTick') || {};
let now = Date.now();

Object.keys(lines).forEach(id => {
  let line = lines[id];
  if (line.isRunning && !line.activeFault && !globalState.isShiftBreak) {
     line.operatingTime += 1;
     if (!lastTick[id]) lastTick[id] = now;
     let elapsed = (now - lastTick[id]) / 1000;
     if (elapsed >= line.taktTime) {
        let parts = Math.floor(elapsed / line.taktTime);
        line.partsCount += parts;
        lastTick[id] = now - ((elapsed % line.taktTime) * 1000);
     }
  } else {
     line.downtime += 1;
     lastTick[id] = now;
  }
});

global.set('linesState', lines);
global.set('lastTick', lastTick);

msg.payload = JSON.stringify({ type: 'STATE_UPDATE', lines: lines, globalState: globalState });
return msg;

try {
  let cmd = JSON.parse(msg.payload);
  let lines = global.get('linesState') || {};
  let globalState = global.get('globalState') || { isShiftBreak: false, shiftDuration: 3600 };

  if (cmd.action === 'UPDATE_LINE') {
     let id = cmd.lineId;
     if (lines[id]) {
        lines[id] = { ...lines[id], ...cmd.updates };
     }
  }
  if (cmd.action === 'UPDATE_GLOBAL') {
     globalState = { ...globalState, ...cmd.updates };
     global.set('globalState', globalState);
  }

  global.set('linesState', lines);

  // Force immediate broadcast back to UI
  msg.payload = JSON.stringify({ type: 'STATE_UPDATE', lines: lines, globalState: globalState });
  return msg;
} catch(e) {
  node.error("Command Error", e);
  return null;
}
